insert into public.question_options (id, question_id, option_text, position)
values
  ('40000000-0000-4000-8000-000000001f45', '30000000-0000-4000-8000-0000000007d1', 'Keep Satisfied: Provide concise, high-level milestone updates focused on risk mitigation and ROI.', 1),
  ('40000000-0000-4000-8000-000000001f46', '30000000-0000-4000-8000-0000000007d1', 'Manage Closely: Require them to attend daily 30-minute agile standups.', 2),
  ('40000000-0000-4000-8000-000000001f47', '30000000-0000-4000-8000-0000000007d1', 'Monitor Only: Send them raw technical server logs at the end of every sprint.', 3),
  ('40000000-0000-4000-8000-000000001f48', '30000000-0000-4000-8000-0000000007d1', 'Keep Informed: Engage them in detailed user interface wireframe review sessions.', 4),
  ('40000000-0000-4000-8000-000000001f49', '30000000-0000-4000-8000-0000000007d2', 'Mandatory late-night video conferences twice daily for all developer teams.', 1),
  ('40000000-0000-4000-8000-000000001f4a', '30000000-0000-4000-8000-0000000007d2', 'Centralized kanban task boards with daily asynchronous standup threads and integrated code repositories.', 2),
  ('40000000-0000-4000-8000-000000001f4b', '30000000-0000-4000-8000-0000000007d2', 'Replacing all ticketing systems with unorganized team messaging channels.', 3),
  ('40000000-0000-4000-8000-000000001f4c', '30000000-0000-4000-8000-0000000007d2', 'Relying exclusively on weekly PDF status reports distributed via email attachments.', 4),
  ('40000000-0000-4000-8000-000000001f4d', '30000000-0000-4000-8000-0000000007d3', 'Storing project files in a public cloud folder protected only by a shared master password.', 1),
  ('40000000-0000-4000-8000-000000001f4e', '30000000-0000-4000-8000-0000000007d3', 'Distributing unencrypted patient samples to external QA vendors via standard email.', 2),
  ('40000000-0000-4000-8000-000000001f4f', '30000000-0000-4000-8000-0000000007d3', 'Role-based access controls (RBAC) with end-to-end encryption and audit logging for all shared project repositories.', 3),
  ('40000000-0000-4000-8000-000000001f50', '30000000-0000-4000-8000-0000000007d3', 'Disabling file access logs to maximize server download performance during testing.', 4),
  ('40000000-0000-4000-8000-000000001f51', '30000000-0000-4000-8000-0000000007d4', 'Conceal the vulnerability until the post-launch maintenance patch cycle next quarter.', 1),
  ('40000000-0000-4000-8000-000000001f52', '30000000-0000-4000-8000-0000000007d4', 'Notify public news media immediately before conducting internal technical verification.', 2),
  ('40000000-0000-4000-8000-000000001f53', '30000000-0000-4000-8000-0000000007d4', 'Unilaterally shut down the entire enterprise network without notifying business unit leaders.', 3),
  ('40000000-0000-4000-8000-000000001f54', '30000000-0000-4000-8000-0000000007d4', 'Escalate immediately to the Risk Committee and Technical Lead with a vulnerability summary and proposed remediation timeline.', 4),
  ('40000000-0000-4000-8000-000000001f55', '30000000-0000-4000-8000-0000000007d5', 'COBIT combined with ITIL service management frameworks.', 1),
  ('40000000-0000-4000-8000-000000001f56', '30000000-0000-4000-8000-0000000007d5', 'ANSI/ASHRAE datacenter cooling standards.', 2),
